import { NextResponse } from 'next/server'
import { execFileSync } from 'node:child_process'
import fs from 'node:fs'
import path from 'node:path'

export const runtime = 'nodejs'
export const dynamic = 'force-dynamic'

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url)
    const refresh = searchParams.get('refresh') === 'true'
    
    const cacheFile = path.join(process.cwd(), 'data', 'cache', 'timetable.json')
    
    // If not refreshing and cache exists, return cached data
    if (!refresh && fs.existsSync(cacheFile)) {
      const cached = fs.readFileSync(cacheFile, 'utf8')
      return NextResponse.json(JSON.parse(cached), { headers: { 'Cache-Control': 'no-store' } })
    }
    
    // Parse and create/update cache
    const scriptPath = path.join(process.cwd(), 'scripts', 'parse-timetable.js')
    const output = execFileSync('node', [scriptPath], {
      encoding: 'utf8',
      cwd: process.cwd(),
      maxBuffer: 256 * 1024 * 1024,
      timeout: 60000,
    })

    const parsed = JSON.parse(output)
    return NextResponse.json(parsed, { headers: { 'Cache-Control': 'no-store' } })
  } catch (error) {
    const message =
      error instanceof Error
        ? error.message
        : 'Failed to parse timetable.'
    return NextResponse.json({ error: message }, { status: 500 })
  }
}
